class Item {
    private String code;
    private String name;
    private Price purchasePrice;
    private Price sellingPrice;
    private int stockItem;

    public Item(String code, String name, Price purchasePrice, Price sellingPrice, int stockItem) {
        this.code = code;
        this.name = name;
        this.purchasePrice = purchasePrice;
        this.sellingPrice = sellingPrice;
        this.stockItem = stockItem;
    }

    public String getCode() {
        return code;
    }

    public void setName(String name) {
        this.name = name;
    }

    public String getName() {
        return name;
    }

    public void setPurchasePrice(Price purchasePrice) {
        this.purchasePrice = purchasePrice;
    }

    public Price getPurchasePrice() {
        return purchasePrice;
    }

    public void setSellingPrice(Price sellingPrice) {
        this.sellingPrice = sellingPrice;
    }

    public Price getSellingPrice() {
        return sellingPrice;
    }

    public void setStockItem(int stockItem) {
        this.stockItem = stockItem;
    }

    public int getStockItem() {
        return stockItem;
    }
}

class ItemCollection {
    private Map<String, Item> itemMap;

    public ItemCollection() {
        itemMap = new HashMap<>();
    }

    public void addItem(Item item) {
        itemMap.put(item.getCode(), item);
    }

    public void removeItem(String code) {
        itemMap.remove(code);
    }

    public boolean containsItem(String code) {
        return itemMap.containsKey(code);
    }

    public Item getItem(String code) {
        return itemMap.get(code);
    }
}

class Price {
    private double value;

    public Price(double value) {
        this.value = value;
    }

    public double getValue() {
        return value;
    }

    public void setValue(double value) {
        this.value = value;
    }

    public String toString() {
        return String.format("%.0f", value);
    }
}

