private async Task<Video> GetVideoDetailsAsync(VideoSearchResult video, CancellationToken cancellationToken)
{
// Video Details fetch and process…
var videoDetails = await youtube.Videos.GetAsync(video.Id, cancellationToken);
var streamInfo = await youtube.Videos.Streams.GetManifestAsync(video.Id, cancellationToken);
var audioStreamInfo = streamInfo.GetAudioOnlyStreams().GetWithHighestBitrate();

// CancellationToken kontrolü sonrasında yeni Video nesnesi oluşturulacak
if (cancellationToken.IsCancellationRequested)
{
throw new OperationCanceledException(cancellationToken);
}

// Video nesnesinin oluşturulması
return new Video
{
Id = video.Id,
Title = video.Title,
Author = video.Author.Title,
ThumbnailUrl = video.Thumbnails.GetWithHighestResolution()?.Url,
Duration = video.Duration?.ToString(),
Likes = (int)videoDetails.Engagement.LikeCount,
ViewCount = (int)videoDetails.Engagement.ViewCount,
StreamUrl = audioStreamInfo?.Url,
AudioStreamInfo = audioStreamInfo
};
// Semaphore release işlemi çağıran metod tarafından yapılacak
}


