function res = smoothing(phi,f,h)
N = size(phi, 1) - 1;
res = phi;
for i = 2:N
for j = 2:N
res(i, j) = (phi(i+1, j)+res(i-1, j)+phi(i, j+1)+res(i, j-1)+h^2f(i, j))/4;

end
end
