function res = cancha(phi,f,h)
N = size(phi, 1) - 1;
res = zeros(N+1, N+1);
res(2:N, 2:N) = f(2:N, 2:N)-(phi(1:N-1, 2:N)-2phi(2:N, 2:N)+phi(3:N+1, 2:N)+phi(2:N, 1:N-1)-2phi(2:N, 2:N)+phi(2:N, 3:N+1))/h^2;
end

